const webhook = $('Webhook').first().json;
const agency = (webhook.body?.agency || '').toLowerCase();
const dataType = webhook.body?.data_type || 'all';

let intel = [], opps = [], comps = [], actions = [];
try { intel = $('Query Intel').all().map(i => i.json); } catch {}
try { opps = $('Query Opportunities').all().map(i => i.json); } catch {}
try { comps = $('Query Competitors').all().map(i => i.json); } catch {}
try { actions = $('Query Actions').all().map(i => i.json); } catch {}

const filterByAgency = (arr) => {
  if (!agency) return arr;
  return arr.filter(r => {
    const a = (r.agency || r.target || '').toLowerCase();
    return a.includes(agency) || agency.includes(a);
  });
};

return [{ json: {
  agency: webhook.body?.agency || 'All Agencies',
  data_type: dataType,
  generated_at: new Date().toISOString(),
  intel_log: filterByAgency(intel),
  opportunity_alerts: filterByAgency(opps),
  competitor_cache: filterByAgency(comps),
  action_items: filterByAgency(actions),
  sources: [
    { source: 'gda_intelligence_log', url: 'Internal Postgres', date: new Date().toISOString() },
    { source: 'gda_opportunity_alerts', url: 'Internal Postgres', date: new Date().toISOString() },
    { source: 'gda_competitor_cache', url: 'Internal Postgres', date: new Date().toISOString() },
    { source: 'gda_action_items', url: 'Internal Postgres', date: new Date().toISOString() },
    { source: 'USASpending.gov', url: 'https://api.usaspending.gov/api/v2/', date: new Date().toISOString() }
  ]
}}];

if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers["x-gda-auth"] || headers["x-gda-key"] || body.auth_key || body.deploy_key || "";
const validKeys = [$env.GDA_DEPLOY_KEY_2026, $env.GDA_API_KEY_2026, $env.GDA_WEBHOOK_SECRET_2026];
if (!validKeys.includes(auth)) {
  const origin = (headers.origin || headers.referer || "").toLowerCase();
  const trusted = ["gda.csr-llc.tech","n8n.csr-llc.tech","localhost","gdacommand.retool.com"];
  if (!trusted.some(o => origin.includes(o))) throw new Error("Unauthorized");
}
return [{ json: body }];
